type User { id: ID!, username: String!, email: String!, posts: [Post!]!, createdAt: DateTime! }

type Post { id: ID!, title: String!, content: String!, author: User!, comments: [Comment!]!, likes: Int!, createdAt: DateTime! }

type Comment { id: ID!, content: String!, author: User!, post: Post!, createdAt: DateTime! }

type Query {
  user(id: ID!): User
  users(limit: Int, offset: Int): [User!]!
  post(id: ID!): Post
  posts(limit: Int, offset: Int): [Post!]!
}

type Mutation {
  createUser(username: String!, email: String!, password: String!): User!
  createPost(title: String!, content: String!): Post!
  createComment(postId: ID!, content: String!): Comment!
  likePost(postId: ID!): Post!
}

